type HistoryEntry = number | DurationObservation | { observations: DurationObservation[] }
export type DurationHistory = Record<string, HistoryEntry>

function observations(entry: HistoryEntry): DurationObservation[] {
  if (typeof entry === 'number') { return [{ duration: entry, recordedAt: 0 }] }
  if ('observations' in entry) { return entry.observations }
  return [entry]
}

export async function readDurationHistory(root: string, path: string): Promise<DurationHistory | null> {
  try {
    const value = JSON.parse(await fs.readFile(resolve(root, path), 'utf8'))
    return value && typeof value === 'object' && !Array.isArray(value) ? value : null
  }
  catch {
    return null
  }
}

export function durationsFromHistory(history: DurationHistory, ttl: number, smoothing: 'latest' | 'average' | 'p95' | 'median', now = Date.now()): Map<string, number> {
  const result = new Map<string, number>()
  const expiresAt = now - ttl
  for (const [path, entry] of Object.entries(history)) {
    const valid = observations(entry).filter(item => Number.isFinite(item.duration) && Number.isFinite(item.recordedAt) && (!ttl || item.recordedAt === 0 || item.recordedAt >= expiresAt))
    if (valid.length) { result.set(path, smoothDurations(valid, smoothing)) }
  }
  return result
}

